/*\n  # Create Products and Orders Tables\n\n  1. New Tables\n    - `products`\n      - `id` (uuid, primary key)\n      - `name` (text)\n      - `description` (text)\n      - `price` (decimal)\n      - `image_url` (text)\n      - `category` (text)\n      - `stock_quantity` (integer)\n      - `is_active` (boolean)\n      - `created_at` (timestamp)\n      - `updated_at` (timestamp)\n\n    - `orders`\n      - `id` (uuid, primary key)\n      - `user_id` (uuid, foreign key to auth.users)\n      - `status` (enum: pending, processing, shipped, delivered, cancelled)\n      - `total_amount` (decimal)\n      - `shipping_address` (jsonb)\n      - `created_at` (timestamp)\n      - `updated_at` (timestamp)\n\n    - `order_items`\n      - `id` (uuid, primary key)\n      - `order_id` (uuid, foreign key to orders)\n      - `product_id` (uuid, foreign key to products)\n      - `quantity` (integer)\n      - `price` (decimal)\n      - `created_at` (timestamp)\n\n  2. Security\n    - Enable RLS on all tables\n    - Admins can do everything\n    - Users can view products\n    - Users can view/create their own orders\n*/\n\n-- Create order status enum\nDO $$ BEGIN\n  CREATE TYPE order_status AS ENUM ('pending', 'processing', 'shipped', 'delivered', 'cancelled');
\nEXCEPTION\n  WHEN duplicate_object THEN null;
\nEND $$;
\n\n-- Create products table\nCREATE TABLE IF NOT EXISTS products (\n  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),\n  name text NOT NULL,\n  description text,\n  price decimal(10,2) NOT NULL,\n  image_url text,\n  category text,\n  stock_quantity integer DEFAULT 0,\n  is_active boolean DEFAULT true,\n  created_at timestamptz DEFAULT now(),\n  updated_at timestamptz DEFAULT now()\n);
\n\n-- Create orders table\nCREATE TABLE IF NOT EXISTS orders (\n  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),\n  user_id uuid REFERENCES auth.users(id) ON DELETE CASCADE,\n  status order_status DEFAULT 'pending',\n  total_amount decimal(10,2) NOT NULL,\n  shipping_address jsonb,\n  created_at timestamptz DEFAULT now(),\n  updated_at timestamptz DEFAULT now()\n);
\n\n-- Create order_items table\nCREATE TABLE IF NOT EXISTS order_items (\n  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),\n  order_id uuid REFERENCES orders(id) ON DELETE CASCADE,\n  product_id uuid REFERENCES products(id) ON DELETE CASCADE,\n  quantity integer NOT NULL,\n  price decimal(10,2) NOT NULL,\n  created_at timestamptz DEFAULT now()\n);
\n\n-- Enable RLS\nALTER TABLE products ENABLE ROW LEVEL SECURITY;
\nALTER TABLE orders ENABLE ROW LEVEL SECURITY;
\nALTER TABLE order_items ENABLE ROW LEVEL SECURITY;
\n\n-- Products policies\nCREATE POLICY "Anyone can view active products"\n  ON products FOR SELECT\n  USING (is_active = true OR auth.uid() IS NOT NULL);
\n\nCREATE POLICY "Admins can insert products"\n  ON products FOR INSERT\n  TO authenticated\n  WITH CHECK ((SELECT is_admin FROM profiles WHERE id = auth.uid()) = true);
\n\nCREATE POLICY "Admins can update products"\n  ON products FOR UPDATE\n  TO authenticated\n  USING ((SELECT is_admin FROM profiles WHERE id = auth.uid()) = true)\n  WITH CHECK ((SELECT is_admin FROM profiles WHERE id = auth.uid()) = true);
\n\nCREATE POLICY "Admins can delete products"\n  ON products FOR DELETE\n  TO authenticated\n  USING ((SELECT is_admin FROM profiles WHERE id = auth.uid()) = true);
\n\n-- Orders policies\nCREATE POLICY "Users can view own orders or admins can view all"\n  ON orders FOR SELECT\n  TO authenticated\n  USING (\n    user_id = auth.uid() OR\n    (SELECT is_admin FROM profiles WHERE id = auth.uid()) = true\n  );
\n\nCREATE POLICY "Authenticated users can create orders"\n  ON orders FOR INSERT\n  TO authenticated\n  WITH CHECK (user_id = auth.uid());
\n\nCREATE POLICY "Admins can update orders"\n  ON orders FOR UPDATE\n  TO authenticated\n  USING ((SELECT is_admin FROM profiles WHERE id = auth.uid()) = true)\n  WITH CHECK ((SELECT is_admin FROM profiles WHERE id = auth.uid()) = true);
\n\nCREATE POLICY "Admins can delete orders"\n  ON orders FOR DELETE\n  TO authenticated\n  USING ((SELECT is_admin FROM profiles WHERE id = auth.uid()) = true);
\n\n-- Order items policies\nCREATE POLICY "Users can view own order items or admins can view all"\n  ON order_items FOR SELECT\n  TO authenticated\n  USING (\n    EXISTS (\n      SELECT 1 FROM orders WHERE orders.id = order_items.order_id AND orders.user_id = auth.uid()\n    ) OR\n    (SELECT is_admin FROM profiles WHERE id = auth.uid()) = true\n  );
\n\nCREATE POLICY "Authenticated users can create order items"\n  ON order_items FOR INSERT\n  TO authenticated\n  WITH CHECK (\n    EXISTS (\n      SELECT 1 FROM orders WHERE orders.id = order_items.order_id AND orders.user_id = auth.uid()\n    )\n  );
\n\nCREATE POLICY "Admins can update order items"\n  ON order_items FOR UPDATE\n  TO authenticated\n  USING ((SELECT is_admin FROM profiles WHERE id = auth.uid()) = true)\n  WITH CHECK ((SELECT is_admin FROM profiles WHERE id = auth.uid()) = true);
\n\nCREATE POLICY "Admins can delete order items"\n  ON order_items FOR DELETE\n  TO authenticated\n  USING ((SELECT is_admin FROM profiles WHERE id = auth.uid()) = true);
\n\n-- Create indexes for better performance\nCREATE INDEX IF NOT EXISTS idx_products_category ON products(category);
\nCREATE INDEX IF NOT EXISTS idx_products_is_active ON products(is_active);
\nCREATE INDEX IF NOT EXISTS idx_orders_user_id ON orders(user_id);
\nCREATE INDEX IF NOT EXISTS idx_orders_status ON orders(status);
\nCREATE INDEX IF NOT EXISTS idx_order_items_order_id ON order_items(order_id);
\nCREATE INDEX IF NOT EXISTS idx_order_items_product_id ON order_items(product_id);
\n;
